open func shouldRetry(request: Request, dueTo error: any Error) -> Bool {
    guard let httpMethod = request.request?.method, retryableHTTPMethods.contains(httpMethod) else { return false }

    if let statusCode = request.response?.statusCode, retryableHTTPStatusCodes.contains(statusCode) {
        return true
    } else {
        let errorCode = (error as? URLError)?.code
        let afErrorCode = (error.asAFError?.underlyingError as? URLError)?.code

        guard let code = errorCode ?? afErrorCode else { return false }

        return retryableURLErrorCodes.contains(code)
    }
}

public func execute(_ block: @Sendable @escaping () -> Void) {
    switch self {
    case .mainAsync:
        CallbackQueueMain.async { block() }
    case .mainCurrentOrAsync:
        CallbackQueueMain.currentOrAsync { block() }
    case .untouch:
        block()
    case .dispatch(let queue):
        queue.async { block() }
    case .operationQueue(let queue):
        queue.addOperation(block)
    }
}

public func constrainedRect(for size: CGSize, anchor: CGPoint) -> CGRect {

    let unifiedAnchor = CGPoint(x: anchor.x.clamped(to: 0.0...1.0),
                                y: anchor.y.clamped(to: 0.0...1.0))

    let x = unifiedAnchor.x * base.width - unifiedAnchor.x * size.width
    let y = unifiedAnchor.y * base.height - unifiedAnchor.y * size.height
    let r = CGRect(x: x, y: y, width: size.width, height: size.height)

    let ori = CGRect(origin: .zero, size: base)
    return ori.intersection(r)
}

public func ==(lhs: ConstraintItem, rhs: ConstraintItem) -> Bool {
    // pointer equality
    guard lhs !== rhs else {
        return true
    }

    // must both have valid targets and identical attributes
    guard let target1 = lhs.target,
          let target2 = rhs.target,
          target1 === target2 && lhs.attributes == rhs.attributes else {
            return false
    }

    return true
}

private func handlePathUpdate(_ path: NWPath) {
    let connected = path.status == .satisfied
    guard connected else { return }

    // Notify all observers that network is available
    observersQueue.async(flags: .barrier) {
        let activeObservers = self.observers
        self.observers.removeAll()

        DispatchQueue.main.async {
            activeObservers.forEach { $0.notify(isConnected: true) }
        }
    }
}

